use rand::Rng;
use rand::distributions::Alphanumeric;

pub fn generate_api_token() -> String {
    let token_length = 40;
    let mut rng = rand::thread_rng();
    let token: String = rng.sample_iter(Alphanumeric)
        .take(token_length)
        .map(char::from)
        .collect();
    token
}